use std::collections::HashMap;

struct DataRow {
    id: usize,
    value: i32,
}

struct DataFrame {
    data: Vec<DataRow>,
    grouping_key: Option<String>,
}
impl DataFrame {
    fn new(data: Vec<DataRow>) -> Self {
        DataFrame { data, grouping_key: None }
    }

    fn set_grouping(&mut self, key: &str) -> &mut Self {
        self.grouping_key = Some(String::from(key));
        self
    }

    fn calculate_lazy(&self) -> HashMap<String, i32> {
        let mut results = HashMap::new();
        if let Some(key) = &self.grouping_key { 
            let total: i32 = self.data.iter().map(|row| row.value).sum();
            results.insert(key.to_string(), total);
        } else {
            let mut sum_all: i32 = 0;
            for row in &self.data { 
                sum_all += row.value;
            }
            results.insert("Total".to_string(), sum_all);
        }
        results
    }
}

fn main() {
    let initial_data = vec![
        DataRow { id: 1, value: 10 },
        DataRow { id: 2, value: 5 },
        DataRow { id: 3, value: 8 } 
    ].into_iter().collect();

    let mut df = DataFrame::new(initial_data);
    df.set_grouping("Region A");

    let final_result = df.calculate_lazy();

    for (key, result) in final_result {
        println!("{}: {}", key, result);
    }
}
